SELECT venue_code                      as venueCode,
       IFNULL(SUM(bet_amount), 0)      as betAmount,
       IFNULL(SUM(win_loss_amount), 0) as winLossAmount,
       IFNULL(SUM(valid_amount), 0)    as validAmount
FROM report_user_venue_win_lose
WHERE user_account = #{userAccount}
  AND site_code = #{siteCode}
  AND day_hour_millis  >=  #{startTime}
  AND day_hour_millis  <=  #{endTime}
GROUP BY venue_code

