mapper.select:
select venue_code, currency, IFNULL(count(DISTINCT user_id),0) as bettorCount, IFNULL(sum(bet_count),0) as betCount, IFNULL(sum(bet_amount),0) as betAmount, IFNULL(sum(valid_amount),0) as validBetAmount, IFNULL(-sum(win_loss_amount),0) as winlossAmount, IFNULL(-sum(user_win_loss_amount),0) as userWinlossAmount, IFNULL(sum(tips_amount),0) as tipsAmount from report_user_venue_win_lose
group by venue_code,currency
ORDER BY ${vo.orderField} ${vo.orderType}
ORDER BY ${vo.orderName} != ${vo.orderValue}, ${vo.orderName} asc
ORDER BY ${vo.orderName} != ${vo.orderValue}, ${vo.orderName} asc, ${vo.orderField} ${vo.orderType}
ORDER BY venue_code,currency,winlossAmount desc,validBetAmount desc,betCount desc

SELECT tab.currency
FROM (
         SELECT currency, COUNT(day_millis) AS countDay
         FROM report_user_venue_win_lose
         WHERE day_millis BETWEEN #{vo.startDayMillisTime} AND #{vo.endDayMillisTime}
           AND venue_type = #{vo.venueType}
           AND site_code = #{vo.siteCode}
         GROUP BY currency
         HAVING COUNT(day_millis) >= #{vo.countDay}
     ) AS tab;

SELECT venue_code as venueCode,
       currency as currency,
       site_code as siteCode,
       IFNULL(sum(valid_amount),0) as validAmount,
       IFNULL(sum(win_loss_amount),0) as winLossAmount,
       IFNULL(sum(user_win_loss_amount),0) as userWinLossAmount
FROM `report_user_venue_win_lose`
where 1 = 1

    AND site_code = #{vo.siteCode}


    AND agent_id IN

        #{value}



    AND day_hour_millis  >=  #{vo.startTime}


    AND day_hour_millis  <=  #{vo.endTime}

group by site_code,venue_code, currency;

select
agent_id AS agentId,
venue_code AS venueCode,
currency AS currency,
IFNULL(-SUM(win_loss_amount),0) AS winLoseAmount,
IFNULL(SUM(tips_amount),0) AS tipsAmount,
IFNULL(SUM(valid_amount),0) AS validBetAmount
from report_user_venue_win_lose
where
site_code = #{vo.siteCode}

    AND agent_id IN

        #{item}



    AND day_hour_millis  >=  #{vo.startTime}


    AND day_hour_millis  <=  #{vo.endTime}


    AND currency = #{vo.currency}

group by agent_id,venue_code,currency

select
COUNT(DISTINCT user_id) AS userIdCount
from report_user_venue_win_lose
where
site_code = #{vo.siteCode}

    AND day_hour_millis  >=  #{vo.startTime}


    AND day_hour_millis  <=  #{vo.endTime}

SELECT day_millis AS dayMillis, currency AS currency, IFNULL(SUM(bet_count), 0) AS betCount, IFNULL(count(DISTINCT user_id),0) as bettorCount, IFNULL(SUM(bet_amount), 0) AS betAmount, IFNULL(-SUM(win_loss_amount), 0) AS winlossAmount, IFNULL(SUM(valid_amount), 0) AS validBetAmount, IFNULL(-SUM(user_win_loss_amount), 0) AS userWinlossAmount, IFNULL(SUM(tips_amount), 0) AS tipsAmount FROM report_user_venue_win_lose where 1 = 1
AND day_hour_millis >= #{vo.startTime}
AND day_hour_millis <= #{vo.endTime}
AND site_code = #{vo.siteCode}
AND venue_code = #{vo.venueCode}
AND currency = #{vo.currency}
group by day_millis,currency order by dayMillis desc

