IFNULL(-SUM(win_loss_amount), 0) AS winloseAmount, IFNULL(SUM(valid_amount), 0) AS validBetAmount, IFNULL(SUM(tips_amount), 0) AS tipsAmount FROM report_user_venue_win_lose
1 = 1
AND day_hour_millis >= #{vo.startTime}
AND day_hour_millis <= #{vo.endTime}
AND site_code in
#{value}
AND currency = #{vo.currency}
group by site_code,currency
ORDER BY ${vo.orderField} ${vo.orderType}
ORDER BY ${vo.orderName} != ${vo.orderValue}, ${vo.orderName} asc
ORDER BY ${vo.orderName} != ${vo.orderValue}, ${vo.orderName} asc, ${vo.orderField} ${vo.orderType}
ORDER BY site_code,currency DESC

