currency AS currency,
IFNULL(SUM(bet_count), 0) AS betNum,
IFNULL(count(DISTINCT user_id),0) as bettorNum,
IFNULL(SUM(bet_amount), 0) AS betAmount,
IFNULL(-SUM(win_loss_amount), 0) AS winloseAmount,
IFNULL(-SUM(user_win_loss_amount), 0) AS betWinLose,
IFNULL(SUM(tips_amount), 0) AS tipsAmount,
IFNULL(SUM(valid_amount), 0) AS validBetAmount
FROM
report_user_venue_win_lose

    1 = 1

        AND day_hour_millis  >=  #{vo.startTime}


