SELECT venue_type as venueType, currency as currency , sum(bet_amount) as betAmount, sum(valid_amount) as validBetAmount, sum(win_loss_amount) as winLossAmount FROM `report_user_venue_win_lose` WHERE agent_id IN
#{value}
AND day_hour_millis >= #{vo.startTime}
AND day_hour_millis <= #{vo.endTime}
GROUP BY venue_type, currency

SELECT agent_id as agentId, venue_type as venueType, currency as currency , sum(bet_amount) as betAmount, sum(valid_amount) as validBetAmount, sum(win_loss_amount) as winLossAmount FROM `report_user_venue_win_lose` WHERE agent_id IS NOT NULL
AND day_hour_millis >= #{vo.startTime}
AND day_hour_millis <= #{vo.endTime}
GROUP BY venue_type, currency, agentId

SELECT a.day_millis,
a.venue_code as venueCode,
sum(a.valid_amount) validBetAmount,
sum(a.valid_amount/b.final_rate) validBetPlatAmount
from report_user_venue_win_lose a join site_currency_info b  on a.currency=b.currency_code and a.site_code=b.site_code
where  1=1
and a.site_code=#{vo.siteCode}

    AND a.day_millis  >=  #{vo.startTime}


    AND a.day_millis  <=  #{vo.endTime}

GROUP BY a.day_millis,a.venue_code

select venue_code as venueCode, currency, SUM(bet_amount) AS betAmount, SUM(win_loss_amount) AS winLossAmount, SUM(valid_amount) AS validAmount from report_user_venue_win_lose a where 1=1 and a.site_code=#{vo.siteCode}
and agent_id IN
#{value}
AND a.day_millis >= #{vo.startTime}
AND a.day_millis <= #{vo.endTime}
group by venue_code,currency order by betAmount desc

SELECT currency currencyCode, IFNULL( sum( valid_amount ), 0 ) AS validAmount, IFNULL( sum( win_loss_amount ), 0 ) AS winLoseAmount, myDay FROM ( SELECT currency, IFNULL(valid_amount , 0 ) AS valid_amount, IFNULL(win_loss_amount , 0 ) AS win_loss_amount, DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(day_hour_millis / 1000), @@session.time_zone, #{timezone}), '%Y-%m-%d') AS myDay FROM report_user_venue_win_lose WHERE site_code = #{siteCode} AND day_hour_millis BETWEEN #{startMillis} AND #{endMillis}
AND currency = #{currencyCode}
) mm GROUP BY myDay,currency

SELECT t.site_code as siteCode, t.agent_id AS agentId, t.agent_account AS agentAccount, t.venue_type as venueType, t.currency as currency, t.day_millis as dayMillis, SUM(t.valid_amount) AS validAmount FROM report_user_venue_win_lose t WHERE t.day_hour_millis >= #{startTime} AND t.day_hour_millis < #{endTime} AND t.agent_id IS NOT NULL AND t.agent_id <> ''
AND t.venue_type = #{venueType}
AND t.site_code = #{siteCode}
AND t.currency = #{currency}
GROUP BY t.site_code, t.agent_id, t.agent_account, t.venue_type, t.currency, t.day_millis ORDER BY validAmount DESC
